/**
 * Calculates the sum of the digits of a number.
 * @param {number} n The number.
 * @returns {number} The sum of the digits.
 */
const digitSumHelper = (n) => {
    let sum = 0;
    let str = String(n);
    for (let i = 0; i < str.length; i++) {
        sum += parseInt(str[i]);
    }
    return sum;
};

/**
 * Precomputes all numbers up to 5000 that have a specific digit sum.
 * @param {number} targetSum The required digit sum.
 * @returns {number[]} An array of numbers <= 5000 with the target digit sum, sorted ascendingly.
 */
const precomputeNumbers = (targetSum) => {
    const validNumbers = [];
    // The upper bound is 5000 based on problem constraints.
    for (let i = 0; i <= 5000; i++) {
        if (digitSumHelper(i) === targetSum) {
            validNumbers.push(i);
        }
    }
    return validNumbers;
};

/**
 * Solves the problem by using dynamic programming.
 * @param {number[]} digitSum The array of required digit sums.
 * @returns {number} The number of distinct valid arrays modulo 10^9 + 7.
 */
const solve = (digitSum) => {
    const MOD = 10**9 + 7;
    const n = digitSum.length;

    // Step 1: Precompute valid numbers for each required digit sum.
    // validNumbers[i] will be a sorted array of numbers <= 5000 with digit sum = i.
    // Since digitSum[i] <= 50, we only need to precompute up to 50.
    const maxDigitSum = 50;
    const precomputedList = Array(maxDigitSum + 1).fill(null).map(() => []);

    for (let s = 0; s <= maxDigitSum; s++) {
        precomputedList[s] = precomputeNumbers(s);
    }

    // Step 2: Dynamic Programming
    // dp[i][j] = Number of ways to form a valid prefix array of length i, 
    // such that the i-th element (arr[i-1]) is the j-th element in validNumbers[digitSum[i-1]].
    //
    // Since the number of valid numbers can be large, a simpler DP state is needed.
    // dp[i][k] = Number of ways to form a valid prefix array of length i, 
    // such that the i-th element (arr[i-1]) is equal to the k-th smallest number 
    // that satisfies digitSum[i-1].

    // Let's refine the DP state:
    // dp[i] = Array where dp[i][j] is the number of ways to form a valid prefix array of length i, 
    // where the i-th element (arr[i-1]) is the j-th valid number for digitSum[i-1].

    // The size of dp[i] is validNumbers[digitSum[i-1]].length.

    // dp[0] is conceptual/base case for the first element.
    // We will use dp[i] to store the counts for the prefix of length i+1 (i.e., for arr[i]).

    // dp_current[j]: Number of ways to form a valid prefix ending at arr[i], 
    // where arr[i] is the j-th valid number for digitSum[i].
    let dp_current;

    // Base case: i = 0 (First element arr[0])
    const S0 = digitSum[0];
    const list0 = precomputedList[S0];

    if (list0.length === 0) {
        return 0; // Impossible to satisfy the first element.
    }

    // For the first element, any valid number is a valid start, so the count is 1 for each.
    dp_current = new Array(list0.length).fill(1);

    // Iterate for i = 1 to n-1
    for (let i = 1; i < n; i++) {
        const Si = digitSum[i];
        const listI = precomputedList[Si];
        const prevList = precomputedList[digitSum[i-1]];

        if (listI.length === 0) {
            return 0; // Impossible to satisfy the current element.
        }

        // dp_next[j]: Number of ways to form a valid prefix of length i+1, 
        // where arr[i] is listI[j].
        const dp_next = new Array(listI.length).fill(0);

        for (let j = 0; j < listI.length; j++) {
            const currentVal = listI[j];
            let count = 0;

            // Sum up dp_current[k] for all previous numbers prevList[k] <= currentVal
            for (let k = 0; k < prevList.length; k++) {
                const prevVal = prevList[k];
                if (prevVal <= currentVal) {
                    count = (count + dp_current[k]) % MOD;
                }
            }
            dp_next[j] = count;
        }

        dp_current = dp_next;
    }

    // Step 3: Final Result
    // The total number of valid arrays is the sum of all entries in the final dp_current array.
    let totalCount = 0;
    for (let i = 0; i < dp_current.length; i++) {
        totalCount = (totalCount + dp_current[i]) % MOD;
    }

    return totalCount;
};

